import React, { useState, useEffect } from 'react';
import api from '../lib/api';

const Sidebar = ({ currentPage, setCurrentPage }) => {
  const [serverHealth, setServerHealth] = useState({ status: 'checking', cpu: 0, memory: 0, disk: 0 });

  useEffect(() => {
    checkServerHealth();
    const interval = setInterval(checkServerHealth, 30000);
    return () => clearInterval(interval);
  }, []);

  const checkServerHealth = async () => {
    try {
      const response = await api.get('/health/');
      setServerHealth({ status: 'healthy', cpu: response.data.cpu || 0, memory: response.data.memory || 0, disk: response.data.disk || 0 });
    } catch (error) { setServerHealth(prev => ({ ...prev, status: 'error' })); }
  };

  const menuItems = [
    { id: 'dashboard', label: 'Dashboard', icon: '📊' },
    { id: 'inventory', label: 'Inventário', icon: '🖥️' },
    { id: 'terminal', label: 'Terminal SSH', icon: '💻' },
    { id: 'backups', label: 'Backups', icon: '💾' },
    { id: 'audit', label: 'Logs de Auditoria', icon: '📋' },
    { id: 'settings', label: 'Configurações', icon: '⚙️' },
  ];

  const getHealthColor = (value) => {
    if (value < 50) return 'bg-green-500';
    if (value < 80) return 'bg-yellow-500';
    return 'bg-red-500';
  };

  return (
    <div className="w-64 bg-gray-800 border-r border-gray-700 flex flex-col">
      <div className="p-6 border-b border-gray-700">
        <div className="flex items-center space-x-3">
          <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-purple-600 rounded-lg flex items-center justify-center"><span className="text-xl">🌐</span></div>
          <div><h1 className="text-lg font-bold text-white">LOR CGR</h1><p className="text-xs text-gray-400">Network Management</p></div>
        </div>
      </div>
      <nav className="flex-1 p-4">
        <ul className="space-y-2">
          {menuItems.map(item => (
            <li key={item.id}>
              <button onClick={() => setCurrentPage(item.id)} className={'w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ' + (currentPage === item.id ? 'bg-blue-600 text-white' : 'text-gray-300 hover:bg-gray-700 hover:text-white')}>
                <span className="text-lg">{item.icon}</span><span className="font-medium">{item.label}</span>
              </button>
            </li>
          ))}
        </ul>
      </nav>
      <div className="p-4 border-t border-gray-700">
        <div className="mb-3 flex items-center justify-between">
          <span className="text-xs font-medium text-gray-400">Status do Servidor</span>
          <span className={'w-2 h-2 rounded-full ' + (serverHealth.status === 'healthy' ? 'bg-green-500' : serverHealth.status === 'error' ? 'bg-red-500' : 'bg-yellow-500')}></span>
        </div>
        {['cpu', 'memory', 'disk'].map(metric => (
          <div key={metric} className="mb-2">
            <div className="flex justify-between text-xs text-gray-400 mb-1"><span className="capitalize">{metric}</span><span>{serverHealth[metric]}%</span></div>
            <div className="h-1.5 bg-gray-700 rounded-full overflow-hidden"><div className={'h-full ' + getHealthColor(serverHealth[metric]) + ' transition-all'} style={{ width: serverHealth[metric] + '%' }}></div></div>
          </div>
        ))}
      </div>
      <div className="p-4 border-t border-gray-700"><p className="text-xs text-gray-500 text-center">LOR CGR v1.0.0</p></div>
    </div>
  );
};

export default Sidebar;
